    SELECT A.ROWID AS rid
    FROM DEV3ITUSER.J_EDI_SND_DB_PAY A
    INNER JOIN DEV1ITUSER.J_EDI_SND_DB_PAY B 
      ON A.SND_SEQ_NO = B.SND_SEQ_NO
    WHERE A.DATA_KOKAN_ID = '000086'
      AND A.EDI_KINO_CATEGORY_CD = 'A140'
      AND A.RCV_SEQ_NO IN (SELECT RCV_SEQ_NO FROM DEV3ITUSER.J_EDI_RCV_DB_SUP)
    ORDER BY A.SND_SEQ_NO
  )
  WHERE ROWNUM <= 500
);
